/**
 * Generates ring-transparent.png from main.png + alpha.png.
 *
 * Problem context:
 * - main.png (371x326): ring photo with uniform grey background (~171,174,179)
 * - alpha.png (309x222): black/white mask (black=background, white=ring)
 *   generated by squishing main.png to 309x222 with different x/y scale factors
 *   (width×0.833, height×0.681), so it must be un-squished back to 371x326
 *
 * Two-pass filter:
 *   1. Mask: alpha.png stretched back to 371x326 via fit:'fill' (reverses squish)
 *      threshold ≥ 230 → opaque (ring body is 250-255; grey edge noise is 209-221)
 *   2. Color distance: if pixel is within 18 units of background grey → transparent
 *      (catches grey background bleed not fully caught by the mask)
 *
 * Bottom artifact: alpha.png rows 210-221 are all-white noise (not ring).
 * These are zeroed out before processing.
 */

import sharp from 'sharp'
import path from 'path'
import { fileURLToPath } from 'url'

const __dirname = path.dirname(fileURLToPath(import.meta.url))
const dir = path.join(__dirname, '../public/images/works/lumiere-ring')

const BG_R = 171, BG_G = 174, BG_B = 179
const BG_THRESH = 18
const MASK_THRESH = 230
const ARTIFACT_ROW_IN_ALPHA = 210

const { width: W, height: H } = await sharp(`${dir}/main.png`).metadata()

const { data: maskRaw } = await sharp(`${dir}/alpha.png`)
  .resize(W, H, { fit: 'fill' })
  .grayscale()
  .raw()
  .toBuffer({ resolveWithObject: true })

const artifactRow = Math.round(ARTIFACT_ROW_IN_ALPHA * H / 222)
for (let y = artifactRow; y < H; y++)
  for (let x = 0; x < W; x++) maskRaw[y * W + x] = 0

const { data: rgb } = await sharp(`${dir}/main.png`)
  .removeAlpha().raw().toBuffer({ resolveWithObject: true })

const rgba = Buffer.alloc(W * H * 4)
for (let i = 0; i < W * H; i++) {
  const r = rgb[i * 3], g = rgb[i * 3 + 1], b = rgb[i * 3 + 2]
  const m = maskRaw[i]
  const dr = r - BG_R, dg = g - BG_G, db = b - BG_B
  const colorDist = Math.sqrt(dr * dr + dg * dg + db * db)
  rgba[i * 4] = r; rgba[i * 4 + 1] = g; rgba[i * 4 + 2] = b
  rgba[i * 4 + 3] = (m >= MASK_THRESH && colorDist >= BG_THRESH) ? 255 : 0
}

await sharp(rgba, { raw: { width: W, height: H, channels: 4 } })
  .png()
  .toFile(`${dir}/ring-transparent.png`)

console.log(`ring-transparent.png generated: ${W}x${H}`)
